"use client"

import { useState, useEffect, useCallback, useRef } from "react"
import { cn } from "@/lib/utils"
import { createClient } from "@/lib/supabase/client"
import { useWorkspace } from "@/lib/hooks/use-workspace"
import { IntegrationLogo } from "@/components/integration-logo"
import { RiskBadge } from "@/components/risk-badge"
import { TimeAgo } from "@/components/time-ago"
import { JsonViewer } from "@/components/json-viewer"
import type { DbEvent } from "@/lib/types"
import {
  Search, Filter, Download, Loader2, ChevronDown, ChevronRight,
  Radio, CircleOff, X,
} from "lucide-react"

const PAGE_SIZE = 50
const STATUS_OPTIONS = ['success', 'error', 'pending', 'skipped']
const RISK_OPTIONS = ['low', 'medium', 'high', 'critical']

export default function ActivityPage() {
  const { workspace } = useWorkspace()
  const supabase = createClient()

  const [events, setEvents] = useState<(DbEvent & { agent_name?: string })[]>([])
  const [loading, setLoading] = useState(true)
  const [page, setPage] = useState(0)
  const [hasMore, setHasMore] = useState(true)
  const [total, setTotal] = useState(0)

  // Filters
  const [search, setSearch] = useState("")
  const [statusFilter, setStatusFilter] = useState<string>("")
  const [riskFilter, setRiskFilter] = useState<string>("")
  const [integrationFilter, setIntegrationFilter] = useState<string>("")
  const [showFilters, setShowFilters] = useState(false)
  const [realtimeOn, setRealtimeOn] = useState(true)

  // Drawer
  const [selectedEvent, setSelectedEvent] = useState<(DbEvent & { agent_name?: string }) | null>(null)

  const fetchEvents = useCallback(async (pageNum = 0) => {
    let query = supabase
      .from('events')
      .select('*, agents(name)', { count: 'exact' })
      .order('created_at', { ascending: false })
      .range(pageNum * PAGE_SIZE, (pageNum + 1) * PAGE_SIZE - 1)

    if (search.trim()) query = query.or(`title.ilike.%${search.trim()}%,type.ilike.%${search.trim()}%`)
    if (statusFilter) query = query.eq('status', statusFilter)
    if (riskFilter) query = query.eq('risk_level', riskFilter)
    if (integrationFilter) query = query.eq('integration', integrationFilter)

    const { data, count } = await query
    if (data) {
      const mapped = data.map((e: Record<string, unknown>) => ({
        ...e,
        agent_name: (e.agents as Record<string, unknown>)?.name as string,
      })) as (DbEvent & { agent_name?: string })[]
      if (pageNum === 0) setEvents(mapped)
      else setEvents(prev => [...prev, ...mapped])
      setHasMore(data.length === PAGE_SIZE)
    }
    if (count !== null) setTotal(count)
    setLoading(false)
  }, [supabase, search, statusFilter, riskFilter, integrationFilter])

  useEffect(() => {
    setLoading(true)
    setPage(0)
    fetchEvents(0)
  }, [fetchEvents])

  // Realtime subscription for live events
  useEffect(() => {
    if (!realtimeOn || !workspace?.id) return
    const sb = createClient()
    const channel = sb
      .channel('activity-live')
      .on(
        'postgres_changes',
        {
          event: 'INSERT',
          schema: 'public',
          table: 'events',
          filter: `workspace_id=eq.${workspace.id}`,
        },
        (payload) => {
          const evt = payload.new as DbEvent & { agent_name?: string }
          setEvents((prev) => [evt, ...prev])
          setTotal((t) => t + 1)
        }
      )
      .subscribe()

    return () => { sb.removeChannel(channel) }
  }, [realtimeOn, workspace?.id])

  function loadMore() {
    const next = page + 1
    setPage(next)
    fetchEvents(next)
  }

  function exportCSV() {
    const header = 'Time,Agent,Type,Integration,Status,Risk,Title'
    const rows = events.map(e =>
      `"${e.created_at}","${e.agent_name || ''}","${e.type}","${e.integration || ''}","${e.status}","${e.risk_level}","${(e.title || '').replace(/"/g, '""')}"`
    )
    const blob = new Blob([header + '\n' + rows.join('\n')], { type: 'text/csv' })
    const url = URL.createObjectURL(blob)
    const a = document.createElement('a')
    a.href = url
    a.download = `activity-export-${new Date().toISOString().slice(0, 10)}.csv`
    a.click()
    URL.revokeObjectURL(url)
  }

  function clearFilters() {
    setSearch("")
    setStatusFilter("")
    setRiskFilter("")
    setIntegrationFilter("")
  }

  const hasActiveFilters = search || statusFilter || riskFilter || integrationFilter

  return (
    <div className="flex flex-col gap-5 p-6">
      <div className="flex items-center justify-between gap-4 flex-wrap">
        <div>
          <h1 className="text-xl font-semibold text-text-primary">Activity Log</h1>
          <p className="text-[13px] text-text-secondary">{total.toLocaleString()} events</p>
        </div>
        <div className="flex items-center gap-2">
          <button onClick={() => setRealtimeOn(!realtimeOn)}
            className={cn("flex items-center gap-1.5 rounded-md border px-3 py-1.5 text-[12px] font-medium transition-colors",
              realtimeOn ? "border-success/30 bg-success/10 text-success" : "border-border-base bg-surface-1 text-text-tertiary"
            )}>
            {realtimeOn ? <Radio className="h-3.5 w-3.5" /> : <CircleOff className="h-3.5 w-3.5" />}
            {realtimeOn ? 'Live' : 'Paused'}
          </button>
          <button onClick={exportCSV}
            className="flex items-center gap-1.5 rounded-md border border-border-base bg-surface-1 px-3 py-1.5 text-[12px] font-medium text-text-secondary hover:text-text-primary transition-colors">
            <Download className="h-3.5 w-3.5" /> Export
          </button>
        </div>
      </div>

      {/* Search + Filter Bar */}
      <div className="flex items-center gap-2 flex-wrap">
        <div className="relative flex-1 min-w-[200px]">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-3.5 w-3.5 text-text-tertiary" />
          <input type="text" value={search} onChange={e => setSearch(e.target.value)}
            placeholder="Search events..."
            className="h-9 w-full rounded-md border border-border-base bg-surface-1 pl-9 pr-3 text-[13px] text-text-primary focus:border-amber focus:outline-none" />
        </div>
        <button onClick={() => setShowFilters(!showFilters)}
          className={cn("flex items-center gap-1.5 rounded-md border px-3 py-2 text-[12px] font-medium transition-colors",
            showFilters || hasActiveFilters ? "border-amber bg-amber-dim text-amber" : "border-border-base bg-surface-1 text-text-secondary"
          )}>
          <Filter className="h-3.5 w-3.5" /> Filters
          {hasActiveFilters && <span className="rounded-full bg-amber px-1.5 text-[10px] text-primary-foreground font-bold">!</span>}
        </button>
        {hasActiveFilters && (
          <button onClick={clearFilters} className="text-[12px] text-text-tertiary hover:text-text-secondary transition-colors">
            <X className="h-3.5 w-3.5" />
          </button>
        )}
      </div>

      {showFilters && (
        <div className="flex items-center gap-3 flex-wrap rounded-lg border border-border-subtle bg-surface-1 p-3">
          <div>
            <label className="mb-1 block text-[10px] font-medium text-text-tertiary">Status</label>
            <select value={statusFilter} onChange={e => setStatusFilter(e.target.value)}
              className="h-8 rounded-md border border-border-base bg-surface-2 px-2 text-[12px] text-text-primary focus:border-amber focus:outline-none">
              <option value="">All</option>
              {STATUS_OPTIONS.map(s => <option key={s} value={s} className="capitalize">{s}</option>)}
            </select>
          </div>
          <div>
            <label className="mb-1 block text-[10px] font-medium text-text-tertiary">Risk</label>
            <select value={riskFilter} onChange={e => setRiskFilter(e.target.value)}
              className="h-8 rounded-md border border-border-base bg-surface-2 px-2 text-[12px] text-text-primary focus:border-amber focus:outline-none">
              <option value="">All</option>
              {RISK_OPTIONS.map(r => <option key={r} value={r} className="capitalize">{r}</option>)}
            </select>
          </div>
          <div>
            <label className="mb-1 block text-[10px] font-medium text-text-tertiary">Integration</label>
            <input type="text" value={integrationFilter} onChange={e => setIntegrationFilter(e.target.value)}
              className="h-8 rounded-md border border-border-base bg-surface-2 px-2 text-[12px] text-text-primary focus:border-amber focus:outline-none"
              placeholder="e.g. slack" />
          </div>
        </div>
      )}

      {/* Event table */}
      {loading ? (
        <div className="flex items-center justify-center py-16"><Loader2 className="h-6 w-6 animate-spin text-text-tertiary" /></div>
      ) : events.length === 0 ? (
        <div className="flex flex-col items-center justify-center py-16 gap-2">
          <p className="text-text-secondary text-[13px]">No events found</p>
        </div>
      ) : (
        <>
          <div className="rounded-lg border border-border-subtle bg-surface-1 overflow-x-auto">
            <table className="w-full text-[13px]">
              <thead>
                <tr className="border-b border-border-subtle bg-surface-2">
                  <th className="py-2 px-4 text-left text-[11px] font-medium text-text-tertiary w-8"></th>
                  <th className="py-2 px-4 text-left text-[11px] font-medium text-text-tertiary">Event</th>
                  <th className="py-2 px-4 text-left text-[11px] font-medium text-text-tertiary">Agent</th>
                  <th className="py-2 px-4 text-left text-[11px] font-medium text-text-tertiary">Integration</th>
                  <th className="py-2 px-4 text-left text-[11px] font-medium text-text-tertiary">Status</th>
                  <th className="py-2 px-4 text-left text-[11px] font-medium text-text-tertiary">Risk</th>
                  <th className="py-2 px-4 text-left text-[11px] font-medium text-text-tertiary">Time</th>
                </tr>
              </thead>
              <tbody>
                {events.map(evt => (
                  <tr key={evt.id}
                    onClick={() => setSelectedEvent(selectedEvent?.id === evt.id ? null : evt)}
                    className={cn("border-b border-border-subtle last:border-0 cursor-pointer transition-colors",
                      selectedEvent?.id === evt.id ? "bg-amber/5" : "hover:bg-surface-2/50"
                    )}>
                    <td className="py-2.5 px-4">
                      {evt.integration && <IntegrationLogo provider={evt.integration} size={16} />}
                    </td>
                    <td className="py-2.5 px-4 text-text-primary truncate max-w-[300px]">{evt.title || evt.type}</td>
                    <td className="py-2.5 px-4 text-text-secondary">{evt.agent_name || '—'}</td>
                    <td className="py-2.5 px-4 text-text-secondary capitalize">{evt.integration || '—'}</td>
                    <td className="py-2.5 px-4">
                      <span className={cn("rounded-full px-2 py-0.5 text-[10px] font-bold",
                        evt.status === 'success' ? "bg-success/10 text-success" :
                        evt.status === 'error' ? "bg-red-400/10 text-red-400" :
                        "bg-surface-2 text-text-tertiary"
                      )}>{evt.status}</span>
                    </td>
                    <td className="py-2.5 px-4">{evt.risk_level && <RiskBadge level={evt.risk_level} />}</td>
                    <td className="py-2.5 px-4 text-text-tertiary"><TimeAgo date={evt.created_at} /></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          {hasMore && (
            <button onClick={loadMore}
              className="self-center flex items-center gap-1.5 rounded-md border border-border-base bg-surface-1 px-4 py-2 text-[12px] font-medium text-text-secondary hover:text-text-primary transition-colors">
              Load more
            </button>
          )}
        </>
      )}

      {/* Side drawer */}
      {selectedEvent && (
        <div className="fixed inset-y-0 right-0 w-full max-w-md bg-surface-1 border-l border-border-subtle shadow-lg z-50 flex flex-col">
          <div className="flex items-center justify-between p-4 border-b border-border-subtle">
            <h2 className="text-[14px] font-semibold text-text-primary">Event Details</h2>
            <button onClick={() => setSelectedEvent(null)} className="text-text-tertiary hover:text-text-primary transition-colors">
              <X className="h-4 w-4" />
            </button>
          </div>
          <div className="flex-1 overflow-y-auto p-4 flex flex-col gap-4">
            <div className="grid gap-3 text-[13px]">
              <div className="flex justify-between"><span className="text-text-tertiary">Type</span><span className="text-text-primary">{selectedEvent.type}</span></div>
              <div className="flex justify-between"><span className="text-text-tertiary">Agent</span><span className="text-text-primary">{selectedEvent.agent_name || '—'}</span></div>
              <div className="flex justify-between"><span className="text-text-tertiary">Integration</span><span className="text-text-primary capitalize">{selectedEvent.integration || '—'}</span></div>
              <div className="flex justify-between"><span className="text-text-tertiary">Status</span><span className="text-text-primary">{selectedEvent.status}</span></div>
              <div className="flex justify-between"><span className="text-text-tertiary">Risk</span>{selectedEvent.risk_level ? <RiskBadge level={selectedEvent.risk_level} /> : <span className="text-text-primary">—</span>}</div>
              <div className="flex justify-between"><span className="text-text-tertiary">Created</span><span className="text-text-primary"><TimeAgo date={selectedEvent.created_at} /></span></div>
              {selectedEvent.cost_usd && <div className="flex justify-between"><span className="text-text-tertiary">Cost</span><span className="text-text-primary">${selectedEvent.cost_usd.toFixed(4)}</span></div>}
            </div>
            {selectedEvent.description && (
              <div>
                <div className="text-[11px] font-medium text-text-tertiary mb-1">Description</div>
                <p className="text-[13px] text-text-primary">{selectedEvent.description}</p>
              </div>
            )}
            {selectedEvent.payload && (
              <div>
                <div className="text-[11px] font-medium text-text-tertiary mb-1">Payload</div>
                <div className="rounded-md bg-surface-2 p-3">
                  <JsonViewer data={selectedEvent.payload} />
                </div>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  )
}

"use client"

import { useState, useEffect } from "react"
import { useRouter } from "next/navigation"
import Link from "next/link"
import { cn } from "@/lib/utils"
import { createClient } from "@/lib/supabase/client"
import { useWorkspace } from "@/lib/hooks/use-workspace"
import { toastSuccess, toastError } from "@/lib/supabase/errors"
import { ArrowLeft, Loader2 } from "lucide-react"

const MODEL_OPTIONS = [
  { value: 'claude-sonnet-4-6', label: 'Claude Sonnet 4.6' },
  { value: 'claude-opus-4-6', label: 'Claude Opus 4.6' },
  { value: 'claude-haiku-4-5-20251001', label: 'Claude Haiku 4.5' },
  { value: 'gpt-4o', label: 'GPT-4o' },
  { value: 'gpt-4o-mini', label: 'GPT-4o Mini' },
]

export default function NewAgentPage() {
  const router = useRouter()
  const { workspace, user } = useWorkspace()
  const [saving, setSaving] = useState(false)
  const [activeIntegrations, setActiveIntegrations] = useState<{ id: string; provider: string }[]>([])

  const [name, setName] = useState("")
  const [description, setDescription] = useState("")
  const [role, setRole] = useState("")
  const [model, setModel] = useState("claude-sonnet-4-6")
  const [triggerType, setTriggerType] = useState<"manual" | "schedule" | "webhook" | "event">("manual")
  const [triggerConfig, setTriggerConfig] = useState<Record<string, unknown>>({})
  const [approvalMode, setApprovalMode] = useState<"always" | "never" | "risk_above">("always")
  const [approvalThreshold, setApprovalThreshold] = useState<"low" | "medium" | "high" | "critical">("medium")
  const [selectedIntegrations, setSelectedIntegrations] = useState<string[]>([])
  const [systemPrompt, setSystemPrompt] = useState("")

  useEffect(() => {
    if (!workspace?.id) return
    const supabase = createClient()
    supabase
      .from('integrations_safe')
      .select('id, provider')
      .eq('status', 'active')
      .then(({ data }) => { if (data) setActiveIntegrations(data) })
  }, [workspace?.id])

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    if (!name.trim()) { toastError("Name is required"); return }
    if (!workspace?.id || !user?.id) return

    setSaving(true)
    const supabase = createClient()
    const { data, error } = await supabase
      .from('agents')
      .insert({
        workspace_id: workspace.id,
        name: name.trim(),
        description: description.trim() || null,
        role: role.trim() || null,
        model,
        trigger_type: triggerType,
        trigger_config: Object.keys(triggerConfig).length > 0 ? triggerConfig : null,
        approval_mode: approvalMode,
        approval_threshold: approvalMode === 'risk_above' ? approvalThreshold : null,
        integrations: selectedIntegrations.length > 0 ? selectedIntegrations : null,
        system_prompt: systemPrompt.trim() || null,
        created_by: user.id,
      })
      .select()
      .single()

    setSaving(false)
    if (error) {
      toastError(error)
    } else {
      toastSuccess(`Agent ${name} created successfully`)
      router.push(`/agents/${data.id}`)
    }
  }

  return (
    <div className="flex flex-col gap-5 p-6 max-w-2xl">
      <Link href="/agents" className="flex items-center gap-1.5 text-[13px] text-text-tertiary transition-colors hover:text-text-secondary">
        <ArrowLeft className="h-3.5 w-3.5" /> Back to Agents
      </Link>

      <div>
        <h1 className="text-xl font-semibold text-text-primary">Create Agent</h1>
        <p className="text-[13px] text-text-secondary">Configure a new AI agent for your workspace</p>
      </div>

      <form onSubmit={handleSubmit} className="flex flex-col gap-6">
        {/* Basic Info */}
        <fieldset className="flex flex-col gap-4 rounded-lg border border-border-subtle bg-surface-1 p-4">
          <legend className="text-[13px] font-semibold text-text-primary px-1">Basic Info</legend>
          <div>
            <label className="mb-1.5 block text-[11px] font-medium text-text-secondary">Name *</label>
            <input type="text" value={name} onChange={e => setName(e.target.value)} maxLength={100} required
              className="h-9 w-full rounded-md border border-border-base bg-surface-1 px-3 text-[13px] text-text-primary focus:border-amber focus:outline-none" placeholder="e.g. Lead Qualifier" />
          </div>
          <div>
            <label className="mb-1.5 block text-[11px] font-medium text-text-secondary">Description</label>
            <textarea value={description} onChange={e => setDescription(e.target.value)} rows={2}
              className="w-full rounded-md border border-border-base bg-surface-1 px-3 py-2 text-[13px] text-text-primary focus:border-amber focus:outline-none resize-none" placeholder="What does this agent do?" />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="mb-1.5 block text-[11px] font-medium text-text-secondary">Role</label>
              <input type="text" value={role} onChange={e => setRole(e.target.value)}
                className="h-9 w-full rounded-md border border-border-base bg-surface-1 px-3 text-[13px] text-text-primary focus:border-amber focus:outline-none" placeholder="e.g. Revenue Recovery" />
            </div>
            <div>
              <label className="mb-1.5 block text-[11px] font-medium text-text-secondary">Model</label>
              <select value={model} onChange={e => setModel(e.target.value)}
                className="h-9 w-full rounded-md border border-border-base bg-surface-1 px-3 text-[13px] text-text-primary focus:border-amber focus:outline-none">
                {MODEL_OPTIONS.map(m => <option key={m.value} value={m.value}>{m.label}</option>)}
              </select>
            </div>
          </div>
        </fieldset>

        {/* Trigger Config */}
        <fieldset className="flex flex-col gap-4 rounded-lg border border-border-subtle bg-surface-1 p-4">
          <legend className="text-[13px] font-semibold text-text-primary px-1">Trigger</legend>
          <div>
            <label className="mb-1.5 block text-[11px] font-medium text-text-secondary">Trigger Type</label>
            <select value={triggerType} onChange={e => { setTriggerType(e.target.value as typeof triggerType); setTriggerConfig({}) }}
              className="h-9 w-full rounded-md border border-border-base bg-surface-1 px-3 text-[13px] text-text-primary focus:border-amber focus:outline-none">
              <option value="manual">Manual</option>
              <option value="schedule">Schedule (Cron)</option>
              <option value="webhook">Webhook</option>
              <option value="event">Event-based</option>
            </select>
          </div>
          {triggerType === 'schedule' && (
            <div>
              <label className="mb-1.5 block text-[11px] font-medium text-text-secondary">Cron Expression</label>
              <input type="text" value={(triggerConfig as Record<string, string>).cron || ''} onChange={e => setTriggerConfig({ cron: e.target.value })}
                className="h-9 w-full rounded-md border border-border-base bg-surface-1 px-3 font-mono text-[13px] text-text-primary focus:border-amber focus:outline-none" placeholder="0 */6 * * *" />
              <p className="mt-1 text-[11px] text-text-tertiary">e.g. "0 9 * * 1-5" = weekdays at 9am</p>
            </div>
          )}
          {triggerType === 'webhook' && (
            <div>
              <label className="mb-1.5 block text-[11px] font-medium text-text-secondary">Webhook URL</label>
              <input type="text" readOnly value={`https://opsconductor.kenanwilliam.dev/api/webhooks/[agent-id]`}
                className="h-9 w-full rounded-md border border-border-base bg-surface-2 px-3 font-mono text-[12px] text-text-tertiary focus:outline-none" />
              <p className="mt-1 text-[11px] text-text-tertiary">URL will be generated after creation</p>
            </div>
          )}
        </fieldset>

        {/* Approval Settings */}
        <fieldset className="flex flex-col gap-4 rounded-lg border border-border-subtle bg-surface-1 p-4">
          <legend className="text-[13px] font-semibold text-text-primary px-1">Approval Settings</legend>
          <div className="flex flex-col gap-2">
            {[
              { value: 'always' as const, label: 'Always require approval' },
              { value: 'never' as const, label: 'Never require approval' },
              { value: 'risk_above' as const, label: 'Require above risk threshold' },
            ].map(opt => (
              <label key={opt.value} className="flex items-center gap-2 cursor-pointer">
                <input type="radio" name="approval" value={opt.value} checked={approvalMode === opt.value}
                  onChange={() => setApprovalMode(opt.value)} className="accent-amber" />
                <span className="text-[13px] text-text-primary">{opt.label}</span>
              </label>
            ))}
          </div>
          {approvalMode === 'risk_above' && (
            <div>
              <label className="mb-1.5 block text-[11px] font-medium text-text-secondary">Threshold</label>
              <select value={approvalThreshold} onChange={e => setApprovalThreshold(e.target.value as typeof approvalThreshold)}
                className="h-9 w-full rounded-md border border-border-base bg-surface-1 px-3 text-[13px] text-text-primary focus:border-amber focus:outline-none">
                <option value="low">Low</option>
                <option value="medium">Medium</option>
                <option value="high">High</option>
                <option value="critical">Critical</option>
              </select>
            </div>
          )}
        </fieldset>

        {/* Integrations */}
        {activeIntegrations.length > 0 && (
          <fieldset className="flex flex-col gap-3 rounded-lg border border-border-subtle bg-surface-1 p-4">
            <legend className="text-[13px] font-semibold text-text-primary px-1">Integrations</legend>
            <div className="flex flex-wrap gap-2">
              {activeIntegrations.map(int => (
                <button key={int.provider} type="button"
                  onClick={() => setSelectedIntegrations(prev =>
                    prev.includes(int.provider) ? prev.filter(p => p !== int.provider) : [...prev, int.provider]
                  )}
                  className={cn("flex items-center gap-1.5 rounded-md border px-3 py-1.5 text-[12px] font-medium transition-colors",
                    selectedIntegrations.includes(int.provider)
                      ? "border-amber bg-amber-dim text-amber"
                      : "border-border-subtle bg-surface-2 text-text-secondary hover:text-text-primary"
                  )}>
                  {int.provider}
                </button>
              ))}
            </div>
          </fieldset>
        )}

        {/* System Prompt */}
        <fieldset className="flex flex-col gap-3 rounded-lg border border-border-subtle bg-surface-1 p-4">
          <legend className="text-[13px] font-semibold text-text-primary px-1">System Prompt</legend>
          <textarea value={systemPrompt} onChange={e => setSystemPrompt(e.target.value)} rows={6} maxLength={16384}
            className="w-full rounded-md border border-border-base bg-surface-1 px-3 py-2 font-mono text-[12px] text-text-primary focus:border-amber focus:outline-none resize-none"
            placeholder={`You are a ${role || '[role]'} agent. Your job is to...`} />
          <div className="text-right text-[11px] text-text-tertiary">{systemPrompt.length} / 16,384</div>
        </fieldset>

        {/* Submit */}
        <div className="flex items-center gap-3">
          <button type="submit" disabled={saving || !name.trim()}
            className="flex items-center gap-2 rounded-md bg-amber px-6 py-2 text-[13px] font-semibold text-primary-foreground transition-colors hover:bg-amber-hover disabled:opacity-50">
            {saving && <Loader2 className="h-4 w-4 animate-spin" />}
            Create Agent
          </button>
          <Link href="/agents" className="text-[13px] text-text-tertiary hover:text-text-secondary">Cancel</Link>
        </div>
      </form>
    </div>
  )
}

"use client"

import { useState, useEffect, useCallback } from "react"
import { cn } from "@/lib/utils"
import { createClient } from "@/lib/supabase/client"
import { useWorkspace } from "@/lib/hooks/use-workspace"
import { useRealtimeApprovals } from "@/lib/hooks/use-realtime"
import { toastSuccess, toastError } from "@/lib/supabase/errors"
import { RiskBadge } from "@/components/risk-badge"
import { TimeAgo } from "@/components/time-ago"
import { JsonViewer } from "@/components/json-viewer"
import type { DbApproval } from "@/lib/types"
type Approval = DbApproval
import {
  CheckCircle, XCircle, Clock, Filter, Loader2,
  ChevronDown, ChevronRight, Edit3, Eye,
} from "lucide-react"

type TabFilter = "pending" | "reviewed" | "all"

export default function ApprovalsPage() {
  const { workspace, profile } = useWorkspace()
  const supabase = createClient()

  const [approvals, setApprovals] = useState<(Approval & { agent_name?: string })[]>([])
  const [loading, setLoading] = useState(true)
  const [tab, setTab] = useState<TabFilter>("pending")
  const [actingOn, setActingOn] = useState<string | null>(null)
  const [expandedId, setExpandedId] = useState<string | null>(null)
  const [editingId, setEditingId] = useState<string | null>(null)
  const [editContent, setEditContent] = useState("")
  const [reviewNote, setReviewNote] = useState("")

  const fetchApprovals = useCallback(async () => {
    let query = supabase
      .from('approvals')
      .select('*, agents(name)')
      .order('created_at', { ascending: false })
      .limit(100)

    if (tab === 'pending') query = query.eq('status', 'pending')
    else if (tab === 'reviewed') query = query.in('status', ['approved', 'rejected', 'expired'])

    const { data } = await query
    if (data) {
      setApprovals(data.map((a: Record<string, unknown>) => ({
        ...a,
        agent_name: (a.agents as Record<string, unknown>)?.name as string,
      })) as (Approval & { agent_name?: string })[])
    }
    setLoading(false)
  }, [supabase, tab])

  useEffect(() => {
    setLoading(true)
    fetchApprovals()
  }, [fetchApprovals])

  useRealtimeApprovals(workspace?.id, () => fetchApprovals())

  async function reviewApproval(id: string, decision: 'approved' | 'rejected', note?: string, edited?: string) {
    setActingOn(id)
    const { error } = await supabase.rpc('review_approval', {
      p_approval_id: id,
      p_decision: decision,
      p_note: note || null,
      p_edit_content: edited || null,
    })
    if (error) {
      toastError(error)
    } else {
      toastSuccess(`Approval ${decision}`)
      fetchApprovals()
      setEditingId(null)
      setEditContent("")
      setReviewNote("")
    }
    setActingOn(null)
  }

  async function bulkAction(decision: 'approved' | 'rejected') {
    const pending = approvals.filter(a => a.status === 'pending')
    if (pending.length === 0) return
    if (!confirm(`${decision === 'approved' ? 'Approve' : 'Reject'} all ${pending.length} pending items?`)) return

    for (const a of pending) {
      await supabase.rpc('review_approval', {
        p_approval_id: a.id,
        p_decision: decision,
        p_note: `Bulk ${decision}`,
        p_edit_content: null,
      })
    }
    toastSuccess(`${pending.length} approvals ${decision}`)
    fetchApprovals()
  }

  const pendingCount = approvals.filter(a => a.status === 'pending').length

  function expiryCountdown(expiresAt: string | null) {
    if (!expiresAt) return null
    const diff = new Date(expiresAt).getTime() - Date.now()
    if (diff <= 0) return <span className="text-red-400 text-[11px]">Expired</span>
    const hours = Math.floor(diff / 3600000)
    const mins = Math.floor((diff % 3600000) / 60000)
    return (
      <span className={cn("text-[11px]", hours < 2 ? "text-red-400" : hours < 12 ? "text-amber" : "text-text-tertiary")}>
        {hours}h {mins}m left
      </span>
    )
  }

  return (
    <div className="flex flex-col gap-5 p-6">
      <div className="flex items-center justify-between gap-4 flex-wrap">
        <div>
          <h1 className="text-xl font-semibold text-text-primary">Approvals</h1>
          <p className="text-[13px] text-text-secondary">
            {pendingCount > 0 ? `${pendingCount} pending review` : 'No pending approvals'}
          </p>
        </div>
        {tab === 'pending' && pendingCount > 1 && (
          <div className="flex items-center gap-2">
            <button onClick={() => bulkAction('approved')}
              className="flex items-center gap-1.5 rounded-md bg-success/10 px-3 py-1.5 text-[12px] font-medium text-success hover:bg-success/20 transition-colors">
              <CheckCircle className="h-3.5 w-3.5" /> Approve All
            </button>
            <button onClick={() => bulkAction('rejected')}
              className="flex items-center gap-1.5 rounded-md bg-red-400/10 px-3 py-1.5 text-[12px] font-medium text-red-400 hover:bg-red-400/20 transition-colors">
              <XCircle className="h-3.5 w-3.5" /> Reject All
            </button>
          </div>
        )}
      </div>

      {/* Tabs */}
      <div className="flex gap-1 border-b border-border-subtle">
        {([
          { id: 'pending' as const, label: 'Pending', count: pendingCount },
          { id: 'reviewed' as const, label: 'History', count: null },
          { id: 'all' as const, label: 'All', count: null },
        ]).map(t => (
          <button key={t.id} onClick={() => setTab(t.id)}
            className={cn("flex items-center gap-1.5 px-3 py-2 text-[13px] font-medium border-b-2 -mb-px transition-colors",
              tab === t.id ? "border-amber text-amber" : "border-transparent text-text-tertiary hover:text-text-secondary"
            )}>
            {t.label}
            {t.count !== null && t.count > 0 && (
              <span className="rounded-full bg-amber/15 px-1.5 py-0.5 text-[10px] font-bold text-amber">{t.count}</span>
            )}
          </button>
        ))}
      </div>

      {/* List */}
      {loading ? (
        <div className="flex items-center justify-center py-16"><Loader2 className="h-6 w-6 animate-spin text-text-tertiary" /></div>
      ) : approvals.length === 0 ? (
        <div className="flex flex-col items-center justify-center py-16 gap-2">
          <CheckCircle className="h-10 w-10 text-text-tertiary" />
          <p className="text-text-secondary text-[13px]">{tab === 'pending' ? 'No pending approvals' : 'No approvals found'}</p>
        </div>
      ) : (
        <div className="flex flex-col gap-3">
          {approvals.map(approval => {
            const isExpanded = expandedId === approval.id
            const isEditing = editingId === approval.id
            const isPending = approval.status === 'pending'
            const isActing = actingOn === approval.id

            return (
              <div key={approval.id} className="rounded-lg border border-border-subtle bg-surface-1 overflow-hidden">
                {/* Header row */}
                <button onClick={() => setExpandedId(isExpanded ? null : approval.id)}
                  className="flex items-center justify-between gap-3 w-full p-4 text-left hover:bg-surface-2/50 transition-colors">
                  <div className="flex items-center gap-3 min-w-0 flex-1">
                    {isExpanded ? <ChevronDown className="h-4 w-4 text-text-tertiary shrink-0" /> : <ChevronRight className="h-4 w-4 text-text-tertiary shrink-0" />}
                    <div className="min-w-0 flex-1">
                      <div className="flex items-center gap-2 flex-wrap">
                        <span className="text-[13px] font-medium text-text-primary truncate">{approval.title || 'Untitled Action'}</span>
                        <RiskBadge level={approval.risk_level} />
                        <span className={cn("rounded-full px-2 py-0.5 text-[10px] font-bold",
                          approval.status === 'pending' ? "bg-amber/15 text-amber" :
                          approval.status === 'approved' ? "bg-success/15 text-success" :
                          approval.status === 'rejected' ? "bg-red-400/15 text-red-400" :
                          "bg-surface-2 text-text-tertiary"
                        )}>
                          {approval.status}
                        </span>
                      </div>
                      <div className="flex items-center gap-2 mt-0.5 text-[11px] text-text-tertiary">
                        <span>{approval.agent_name}</span>
                        <span>•</span>
                        <TimeAgo date={approval.created_at} />
                        {isPending && expiryCountdown(approval.expires_at)}
                      </div>
                    </div>
                  </div>
                  {isPending && !isActing && (
                    <div className="flex items-center gap-1.5 shrink-0" onClick={e => e.stopPropagation()}>
                      <button onClick={() => reviewApproval(approval.id, 'approved')}
                        className="flex items-center gap-1 rounded-md bg-success/10 px-2.5 py-1 text-[11px] font-medium text-success hover:bg-success/20 transition-colors">
                        <CheckCircle className="h-3 w-3" /> Approve
                      </button>
                      <button onClick={() => { setEditingId(approval.id); setExpandedId(approval.id); setEditContent(typeof approval.draft_content === 'string' ? approval.draft_content : JSON.stringify(approval.draft_content, null, 2)) }}
                        className="flex items-center gap-1 rounded-md bg-blue-400/10 px-2.5 py-1 text-[11px] font-medium text-blue-400 hover:bg-blue-400/20 transition-colors">
                        <Edit3 className="h-3 w-3" /> Edit
                      </button>
                      <button onClick={() => reviewApproval(approval.id, 'rejected')}
                        className="flex items-center gap-1 rounded-md bg-red-400/10 px-2.5 py-1 text-[11px] font-medium text-red-400 hover:bg-red-400/20 transition-colors">
                        <XCircle className="h-3 w-3" /> Reject
                      </button>
                    </div>
                  )}
                  {isActing && <Loader2 className="h-4 w-4 animate-spin text-amber shrink-0" />}
                </button>

                {/* Expanded content */}
                {isExpanded && (
                  <div className="border-t border-border-subtle p-4 flex flex-col gap-3">
                    {approval.draft_content && !isEditing && (
                      <div>
                        <div className="text-[11px] font-medium text-text-tertiary mb-1">Draft Content</div>
                        <div className="rounded-md bg-surface-2 p-3">
                          {typeof approval.draft_content === 'string' ? (
                            <pre className="text-[12px] text-text-primary font-mono whitespace-pre-wrap">{approval.draft_content}</pre>
                          ) : (
                            <JsonViewer data={approval.draft_content} />
                          )}
                        </div>
                      </div>
                    )}
                    {approval.context && (
                      <div>
                        <div className="text-[11px] font-medium text-text-tertiary mb-1">Context</div>
                        <div className="rounded-md bg-surface-2 p-3">
                          <JsonViewer data={approval.context} />
                        </div>
                      </div>
                    )}
                    {approval.reviewed_by && (
                      <div className="text-[12px] text-text-tertiary">
                        Reviewed <TimeAgo date={approval.reviewed_at || ''} /> {approval.review_note && `— "${approval.review_note}"`}
                      </div>
                    )}

                    {/* Editing mode */}
                    {isEditing && (
                      <div className="flex flex-col gap-3 mt-2">
                        <div>
                          <label className="mb-1 block text-[11px] font-medium text-text-secondary">Edit Draft Content</label>
                          <textarea value={editContent} onChange={e => setEditContent(e.target.value)} rows={8}
                            className="w-full rounded-md border border-border-base bg-surface-2 px-3 py-2 font-mono text-[12px] text-text-primary focus:border-amber focus:outline-none resize-none" />
                        </div>
                        <div>
                          <label className="mb-1 block text-[11px] font-medium text-text-secondary">Review Note (optional)</label>
                          <input type="text" value={reviewNote} onChange={e => setReviewNote(e.target.value)}
                            className="h-8 w-full rounded-md border border-border-base bg-surface-2 px-3 text-[12px] text-text-primary focus:border-amber focus:outline-none"
                            placeholder="Explain your edits..." />
                        </div>
                        <div className="flex items-center gap-2">
                          <button onClick={() => reviewApproval(approval.id, 'approved', reviewNote, editContent)} disabled={isActing}
                            className="flex items-center gap-1.5 rounded-md bg-success/10 px-3 py-1.5 text-[12px] font-medium text-success hover:bg-success/20 transition-colors disabled:opacity-50">
                            {isActing ? <Loader2 className="h-3.5 w-3.5 animate-spin" /> : <CheckCircle className="h-3.5 w-3.5" />}
                            Approve with Edits
                          </button>
                          <button onClick={() => { setEditingId(null); setEditContent(""); setReviewNote("") }}
                            className="text-[12px] text-text-tertiary hover:text-text-secondary transition-colors">
                            Cancel
                          </button>
                        </div>
                      </div>
                    )}
                  </div>
                )}
              </div>
            )
          })}
        </div>
      )}
    </div>
  )
}

import { Loader2 } from "lucide-react"

export default function AuditLoading() {
  return (
    <div className="flex items-center justify-center h-[60vh]">
      <Loader2 className="h-6 w-6 animate-spin text-text-tertiary" />
    </div>
  )
}

"use client"

import { useState, useEffect, useCallback } from "react"
import { cn } from "@/lib/utils"
import { createClient } from "@/lib/supabase/client"
import { useWorkspace } from "@/lib/hooks/use-workspace"
import { TimeAgo } from "@/components/time-ago"
import { JsonViewer } from "@/components/json-viewer"
import { EmptyState } from "@/components/empty-state"
import type { DbAuditLog } from "@/lib/types"
import {
  FileText, Loader2, ChevronDown, ChevronRight, Filter, ShieldAlert,
} from "lucide-react"

const PAGE_SIZE = 50
const ACTION_OPTIONS = ["INSERT", "UPDATE", "DELETE"]

export default function AuditLogPage() {
  const { workspace, profile } = useWorkspace()
  const supabase = createClient()

  const [logs, setLogs] = useState<DbAuditLog[]>([])
  const [loading, setLoading] = useState(true)
  const [page, setPage] = useState(0)
  const [hasMore, setHasMore] = useState(true)
  const [total, setTotal] = useState(0)

  // Filters
  const [actionFilter, setActionFilter] = useState("")
  const [tableFilter, setTableFilter] = useState("")
  const [showFilters, setShowFilters] = useState(false)
  const [expandedId, setExpandedId] = useState<string | null>(null)

  // RBAC: only owner/admin can see this page
  const canAccess = profile?.role === "owner" || profile?.role === "admin"

  const fetchLogs = useCallback(async (pageNum = 0) => {
    if (!canAccess) return

    let query = supabase
      .from("audit_log")
      .select("*", { count: "exact" })
      .order("created_at", { ascending: false })
      .range(pageNum * PAGE_SIZE, (pageNum + 1) * PAGE_SIZE - 1)

    if (actionFilter) query = query.eq("action", actionFilter)
    if (tableFilter) query = query.eq("table_name", tableFilter)

    const { data, count } = await query
    if (data) {
      if (pageNum === 0) setLogs(data as DbAuditLog[])
      else setLogs((prev) => [...prev, ...(data as DbAuditLog[])])
      setHasMore(data.length === PAGE_SIZE)
    }
    if (count !== null) setTotal(count)
    setLoading(false)
  }, [supabase, actionFilter, tableFilter, canAccess])

  useEffect(() => {
    if (!workspace?.id) return
    setLoading(true)
    setPage(0)
    fetchLogs(0)
  }, [fetchLogs, workspace?.id])

  function loadMore() {
    const next = page + 1
    setPage(next)
    fetchLogs(next)
  }

  // 403 for non-admins
  if (!loading && !canAccess) {
    return (
      <div className="flex flex-col items-center justify-center h-[60vh] gap-4">
        <div className="flex h-16 w-16 items-center justify-center rounded-full bg-red-400/10">
          <ShieldAlert className="h-8 w-8 text-red-400" />
        </div>
        <h2 className="text-lg font-semibold text-text-primary">Access Denied</h2>
        <p className="text-[13px] text-text-secondary max-w-xs text-center">
          Only workspace owners and admins can view the audit log.
        </p>
      </div>
    )
  }

  function renderChanges(log: DbAuditLog) {
    if (log.action === "INSERT" && log.new_data) {
      return (
        <div>
          <div className="text-[11px] font-medium text-success mb-1">New Data</div>
          <JsonViewer data={log.new_data} />
        </div>
      )
    }
    if (log.action === "DELETE" && log.old_data) {
      return (
        <div>
          <div className="text-[11px] font-medium text-red-400 mb-1">Deleted Data</div>
          <JsonViewer data={log.old_data} />
        </div>
      )
    }
    if (log.action === "UPDATE") {
      return (
        <div className="grid gap-3 md:grid-cols-2">
          {log.old_data && (
            <div>
              <div className="text-[11px] font-medium text-red-400 mb-1">Old Values</div>
              <JsonViewer data={log.old_data} />
            </div>
          )}
          {log.new_data && (
            <div>
              <div className="text-[11px] font-medium text-success mb-1">New Values</div>
              <JsonViewer data={log.new_data} />
            </div>
          )}
        </div>
      )
    }
    return <span className="text-[12px] text-text-tertiary italic">No data available</span>
  }

  return (
    <div className="flex flex-col gap-5 p-6">
      <div className="flex items-center justify-between gap-4 flex-wrap">
        <div>
          <div className="flex items-center gap-2">
            <FileText className="h-5 w-5 text-amber" />
            <h1 className="text-xl font-semibold text-text-primary">Audit Log</h1>
          </div>
          <p className="text-[13px] text-text-secondary">{total.toLocaleString()} entries</p>
        </div>
        <button
          onClick={() => setShowFilters(!showFilters)}
          className={cn(
            "flex items-center gap-1.5 rounded-md border px-3 py-2 text-[12px] font-medium transition-colors",
            showFilters ? "border-amber bg-amber-dim text-amber" : "border-border-base bg-surface-1 text-text-secondary"
          )}
        >
          <Filter className="h-3.5 w-3.5" /> Filters
        </button>
      </div>

      {showFilters && (
        <div className="flex items-center gap-3 flex-wrap rounded-lg border border-border-subtle bg-surface-1 p-3">
          <div>
            <label className="mb-1 block text-[10px] font-medium text-text-tertiary">Action</label>
            <select
              value={actionFilter}
              onChange={(e) => setActionFilter(e.target.value)}
              className="h-8 rounded-md border border-border-base bg-surface-2 px-2 text-[12px] text-text-primary focus:border-amber focus:outline-none"
            >
              <option value="">All</option>
              {ACTION_OPTIONS.map((a) => (
                <option key={a} value={a}>{a}</option>
              ))}
            </select>
          </div>
          <div>
            <label className="mb-1 block text-[10px] font-medium text-text-tertiary">Table</label>
            <input
              type="text"
              value={tableFilter}
              onChange={(e) => setTableFilter(e.target.value)}
              className="h-8 rounded-md border border-border-base bg-surface-2 px-2 text-[12px] text-text-primary focus:border-amber focus:outline-none"
              placeholder="e.g. agents"
            />
          </div>
        </div>
      )}

      {loading ? (
        <div className="flex items-center justify-center py-16">
          <Loader2 className="h-6 w-6 animate-spin text-text-tertiary" />
        </div>
      ) : logs.length === 0 ? (
        <EmptyState icon={FileText} headline="No audit entries" description="Database changes will appear here as they happen." />
      ) : (
        <>
          <div className="rounded-lg border border-border-subtle bg-surface-1 overflow-x-auto">
            <table className="w-full text-[13px]">
              <thead>
                <tr className="border-b border-border-subtle bg-surface-2">
                  <th className="py-2 px-4 text-left text-[11px] font-medium text-text-tertiary w-8"></th>
                  <th className="py-2 px-4 text-left text-[11px] font-medium text-text-tertiary">Time</th>
                  <th className="py-2 px-4 text-left text-[11px] font-medium text-text-tertiary">Action</th>
                  <th className="py-2 px-4 text-left text-[11px] font-medium text-text-tertiary">Table</th>
                  <th className="py-2 px-4 text-left text-[11px] font-medium text-text-tertiary">Record ID</th>
                  <th className="py-2 px-4 text-left text-[11px] font-medium text-text-tertiary">Actor</th>
                </tr>
              </thead>
              <tbody>
                {logs.map((log) => {
                  const isExpanded = expandedId === log.id
                  return (
                    <>
                      <tr
                        key={log.id}
                        onClick={() => setExpandedId(isExpanded ? null : log.id)}
                        className={cn(
                          "border-b border-border-subtle last:border-0 cursor-pointer transition-colors",
                          isExpanded ? "bg-amber/5" : "hover:bg-surface-2/50"
                        )}
                      >
                        <td className="py-2.5 px-4">
                          {isExpanded ? (
                            <ChevronDown className="h-3.5 w-3.5 text-text-tertiary" />
                          ) : (
                            <ChevronRight className="h-3.5 w-3.5 text-text-tertiary" />
                          )}
                        </td>
                        <td className="py-2.5 px-4 text-text-tertiary">
                          <TimeAgo timestamp={log.created_at} />
                        </td>
                        <td className="py-2.5 px-4">
                          <span
                            className={cn(
                              "rounded-full px-2 py-0.5 text-[10px] font-bold",
                              log.action === "INSERT"
                                ? "bg-success/10 text-success"
                                : log.action === "DELETE"
                                ? "bg-red-400/10 text-red-400"
                                : "bg-blue-400/10 text-blue-400"
                            )}
                          >
                            {log.action}
                          </span>
                        </td>
                        <td className="py-2.5 px-4 font-mono text-text-secondary">
                          {log.table_name || "—"}
                        </td>
                        <td className="py-2.5 px-4 font-mono text-[11px] text-text-tertiary max-w-[200px] truncate">
                          {log.record_id || "—"}
                        </td>
                        <td className="py-2.5 px-4 text-text-secondary">
                          {log.actor?.full_name || log.actor_id?.slice(0, 8) || "system"}
                        </td>
                      </tr>
                      {isExpanded && (
                        <tr key={`${log.id}-detail`} className="border-b border-border-subtle">
                          <td colSpan={6} className="p-4 bg-surface-2/30">
                            {renderChanges(log)}
                          </td>
                        </tr>
                      )}
                    </>
                  )
                })}
              </tbody>
            </table>
          </div>

          {hasMore && (
            <button
              onClick={loadMore}
              className="self-center flex items-center gap-1.5 rounded-md border border-border-base bg-surface-1 px-4 py-2 text-[12px] font-medium text-text-secondary hover:text-text-primary transition-colors"
            >
              Load more
            </button>
          )}
        </>
      )}
    </div>
  )
}

"use client"

import { useState, useEffect, useCallback } from "react"
import { cn } from "@/lib/utils"
import { createClient } from "@/lib/supabase/client"
import { useWorkspace } from "@/lib/hooks/use-workspace"
import { toastSuccess, toastError } from "@/lib/supabase/errors"
import { IntegrationLogo } from "@/components/integration-logo"
import { TimeAgo } from "@/components/time-ago"
import type { DbIntegration } from "@/lib/types"
type Integration = DbIntegration
import {
  Plug, CheckCircle, Plus, Loader2, Trash2, ExternalLink,
} from "lucide-react"

const ALL_PROVIDERS = [
  { provider: "slack", label: "Slack", category: "Communication", description: "Send messages, create channels, post agent updates" },
  { provider: "gmail", label: "Gmail", category: "Communication", description: "Send and draft emails on behalf of agents" },
  { provider: "hubspot", label: "HubSpot", category: "CRM", description: "Manage contacts, deals, and sales pipelines" },
  { provider: "salesforce", label: "Salesforce", category: "CRM", description: "Sync leads, opportunities, and account data" },
  { provider: "stripe", label: "Stripe", category: "Billing", description: "Monitor payments, invoices, and subscriptions" },
  { provider: "notion", label: "Notion", category: "Productivity", description: "Create and update docs, databases, and wikis" },
  { provider: "linear", label: "Linear", category: "Engineering", description: "Create issues, track projects, sync sprints" },
  { provider: "github", label: "GitHub", category: "Engineering", description: "Manage repos, PRs, issues, and deployments" },
  { provider: "jira", label: "Jira", category: "Engineering", description: "Track tickets, epics, and sprint boards" },
  { provider: "calendly", label: "Calendly", category: "Productivity", description: "Book meetings, read availability, cancel events" },
  { provider: "intercom", label: "Intercom", category: "Support", description: "Chat with customers and manage conversations" },
  { provider: "google_calendar", label: "Google Calendar", category: "Productivity", description: "Schedule meetings and manage events" },
  { provider: "google_sheets", label: "Google Sheets", category: "Productivity", description: "Read and write spreadsheet data" },
  { provider: "airtable", label: "Airtable", category: "Productivity", description: "Manage structured data and automations" },
  { provider: "clearbit", label: "Clearbit", category: "Data", description: "Enrich contact data, company lookups" },
  { provider: "zapier", label: "Zapier", category: "Automation", description: "Trigger zaps, pass data to 5000+ apps" },
  { provider: "sendgrid", label: "SendGrid", category: "Communication", description: "Send transactional and marketing emails" },
]

type ViewFilter = "all" | "connected" | "available"

export default function IntegrationsPage() {
  const { workspace } = useWorkspace()
  const supabase = createClient()

  const [integrations, setIntegrations] = useState<Integration[]>([])
  const [loading, setLoading] = useState(true)
  const [view, setView] = useState<ViewFilter>("all")
  const [connecting, setConnecting] = useState<string | null>(null)
  const [disconnecting, setDisconnecting] = useState<string | null>(null)

  const fetchIntegrations = useCallback(async () => {
    const { data } = await supabase
      .from('integrations_safe')
      .select('*')
      .order('created_at', { ascending: false })
    if (data) setIntegrations(data as Integration[])
    setLoading(false)
  }, [supabase])

  useEffect(() => { fetchIntegrations() }, [fetchIntegrations])

  const connectedProviders = new Set(integrations.filter(i => i.status === 'active').map(i => i.provider))

  async function connectProvider(provider: string) {
    if (!workspace?.id) return
    setConnecting(provider)

    // Simulated OAuth flow — inserts integration record
    const { error } = await supabase.from('integrations').insert({
      workspace_id: workspace.id,
      provider,
      status: 'active',
      account_label: `demo@${provider}.com`,
      scopes: ['read', 'write'],
      connected_by: workspace.id,
    })

    if (error) {
      toastError(error)
    } else {
      toastSuccess(`${provider} connected successfully`)
      fetchIntegrations()
    }
    setConnecting(null)
  }

  async function disconnectIntegration(id: string, provider: string) {
    if (!confirm(`Disconnect ${provider}? Agents using this integration will stop working.`)) return
    setDisconnecting(id)
    const { error } = await supabase.from('integrations').update({ status: 'disconnected' }).eq('id', id)
    if (error) {
      toastError(error)
    } else {
      toastSuccess(`${provider} disconnected`)
      fetchIntegrations()
    }
    setDisconnecting(null)
  }

  const filteredProviders = ALL_PROVIDERS.filter(p => {
    if (view === 'connected') return connectedProviders.has(p.provider)
    if (view === 'available') return !connectedProviders.has(p.provider)
    return true
  })

  const categories = [...new Set(filteredProviders.map(p => p.category))]

  if (loading) {
    return (
      <div className="flex items-center justify-center h-[60vh]">
        <Loader2 className="h-6 w-6 animate-spin text-text-tertiary" />
      </div>
    )
  }

  return (
    <div className="flex flex-col gap-5 p-6">
      <div className="flex items-center justify-between gap-4 flex-wrap">
        <div>
          <div className="flex items-center gap-2">
            <Plug className="h-5 w-5 text-amber" />
            <h1 className="text-xl font-semibold text-text-primary">Integrations</h1>
          </div>
          <p className="text-[13px] text-text-secondary">
            {connectedProviders.size} connected · {ALL_PROVIDERS.length - connectedProviders.size} available
          </p>
        </div>
      </div>

      {/* View filters */}
      <div className="flex gap-1 border-b border-border-subtle">
        {([
          { id: 'all' as const, label: 'All' },
          { id: 'connected' as const, label: `Connected (${connectedProviders.size})` },
          { id: 'available' as const, label: 'Available' },
        ]).map(t => (
          <button key={t.id} onClick={() => setView(t.id)}
            className={cn("px-3 py-2 text-[13px] font-medium border-b-2 -mb-px transition-colors",
              view === t.id ? "border-amber text-amber" : "border-transparent text-text-tertiary hover:text-text-secondary"
            )}>
            {t.label}
          </button>
        ))}
      </div>

      {/* Integration grid by category */}
      {categories.map(category => {
        const providers = filteredProviders.filter(p => p.category === category)
        if (providers.length === 0) return null
        return (
          <div key={category}>
            <h3 className="mb-3 text-[11px] font-bold uppercase tracking-wider text-text-tertiary">{category}</h3>
            <div className="grid gap-3 md:grid-cols-2 lg:grid-cols-3">
              {providers.map(p => {
                const isConnected = connectedProviders.has(p.provider)
                const integration = integrations.find(i => i.provider === p.provider && i.status === 'active')
                const isConnecting = connecting === p.provider
                const isDisconnecting = disconnecting === integration?.id

                return (
                  <div key={p.provider}
                    className={cn("flex flex-col gap-3 rounded-lg border bg-surface-1 p-4 transition-colors",
                      isConnected ? "border-success/30" : "border-border-subtle hover:border-border-base"
                    )}>
                    <div className="flex items-center justify-between">
                      <div className="flex items-center gap-2.5">
                        <IntegrationLogo provider={p.provider} size={28} />
                        <div>
                          <div className="text-[13px] font-semibold text-text-primary">{p.label}</div>
                          {isConnected && (
                            <div className="flex items-center gap-1 text-[10px] text-success">
                              <CheckCircle className="h-3 w-3" /> Connected
                            </div>
                          )}
                        </div>
                      </div>
                      {isConnected && integration ? (
                        <button onClick={() => disconnectIntegration(integration.id, p.provider)} disabled={isDisconnecting}
                          className="flex items-center gap-1 rounded-md border border-border-base bg-surface-2 px-2.5 py-1 text-[11px] font-medium text-red-400 hover:text-red-300 transition-colors disabled:opacity-50">
                          {isDisconnecting ? <Loader2 className="h-3 w-3 animate-spin" /> : <Trash2 className="h-3 w-3" />}
                          Disconnect
                        </button>
                      ) : (
                        <button onClick={() => connectProvider(p.provider)} disabled={isConnecting}
                          className="flex items-center gap-1 rounded-md bg-amber px-2.5 py-1 text-[11px] font-semibold text-primary-foreground hover:bg-amber-hover transition-colors disabled:opacity-50">
                          {isConnecting ? <Loader2 className="h-3 w-3 animate-spin" /> : <Plus className="h-3 w-3" />}
                          Connect
                        </button>
                      )}
                    </div>
                    <p className="text-[11px] leading-relaxed text-text-tertiary">{p.description}</p>
                    {isConnected && integration && (
                      <div className="text-[10px] text-text-tertiary border-t border-border-subtle pt-2">
                        Connected <TimeAgo date={integration.connected_at || integration.last_used_at} />
                      </div>
                    )}
                  </div>
                )
              })}
            </div>
          </div>
        )
      })}
    </div>
  )
}

"use client"

import { useState, useEffect } from "react"
import { cn } from "@/lib/utils"
import { createClient } from "@/lib/supabase/client"
import { useWorkspace } from "@/lib/hooks/use-workspace"
import { toastSuccess, toastError } from "@/lib/supabase/errors"
import {
  User, Building2, Shield, Loader2, Save, Trash2,
} from "lucide-react"

type SettingsTab = "profile" | "workspace" | "security"

export default function SettingsPage() {
  const { workspace, profile, refetch: refreshWorkspace } = useWorkspace()
  const supabase = createClient()

  const [tab, setTab] = useState<SettingsTab>("profile")
  const [saving, setSaving] = useState(false)

  // Profile form
  const [displayName, setDisplayName] = useState("")
  const [avatarUrl, setAvatarUrl] = useState("")

  // Workspace form
  const [wsName, setWsName] = useState("")
  const [wsSlug, setWsSlug] = useState("")

  // Security form
  const [currentPassword, setCurrentPassword] = useState("")
  const [newPassword, setNewPassword] = useState("")
  const [confirmPassword, setConfirmPassword] = useState("")

  useEffect(() => {
    if (profile) {
      setDisplayName(profile.full_name || "")
      setAvatarUrl(profile.avatar_url || "")
    }
    if (workspace) {
      setWsName(workspace.name || "")
      setWsSlug(workspace.slug || "")
    }
  }, [profile, workspace])

  async function saveProfile(e: React.FormEvent) {
    e.preventDefault()
    if (!profile) return
    setSaving(true)
    const { error } = await supabase
      .from('profiles')
      .update({
        full_name: displayName.trim() || null,
        avatar_url: avatarUrl.trim() || null,
      })
      .eq('id', profile.id)
    setSaving(false)
    if (error) toastError(error)
    else {
      toastSuccess('Profile updated')
      refreshWorkspace()
    }
  }

  async function saveWorkspace(e: React.FormEvent) {
    e.preventDefault()
    if (!workspace) return
    setSaving(true)
    const { error } = await supabase
      .from('workspaces')
      .update({
        name: wsName.trim(),
        slug: wsSlug.trim().toLowerCase().replace(/[^a-z0-9-]/g, '-'),
      })
      .eq('id', workspace.id)
    setSaving(false)
    if (error) toastError(error)
    else {
      toastSuccess('Workspace updated')
      refreshWorkspace()
    }
  }

  async function changePassword(e: React.FormEvent) {
    e.preventDefault()
    if (newPassword !== confirmPassword) {
      toastError('Passwords do not match')
      return
    }
    if (newPassword.length < 8) {
      toastError('Password must be at least 8 characters')
      return
    }
    setSaving(true)
    const { error } = await supabase.auth.updateUser({ password: newPassword })
    setSaving(false)
    if (error) toastError(error)
    else {
      toastSuccess('Password updated')
      setCurrentPassword("")
      setNewPassword("")
      setConfirmPassword("")
    }
  }

  const TABS = [
    { id: "profile" as const, label: "Profile", icon: User },
    { id: "workspace" as const, label: "Workspace", icon: Building2 },
    { id: "security" as const, label: "Security", icon: Shield },
  ]

  return (
    <div className="flex flex-col gap-5 p-6 max-w-2xl">
      <div>
        <h1 className="text-xl font-semibold text-text-primary">Settings</h1>
        <p className="text-[13px] text-text-secondary">Manage your profile and workspace</p>
      </div>

      <div className="flex gap-1 border-b border-border-subtle">
        {TABS.map(t => (
          <button key={t.id} onClick={() => setTab(t.id)}
            className={cn("flex items-center gap-1.5 px-3 py-2 text-[13px] font-medium border-b-2 -mb-px transition-colors",
              tab === t.id ? "border-amber text-amber" : "border-transparent text-text-tertiary hover:text-text-secondary"
            )}>
            <t.icon className="h-3.5 w-3.5" /> {t.label}
          </button>
        ))}
      </div>

      {/* Profile Tab */}
      {tab === 'profile' && (
        <form onSubmit={saveProfile} className="flex flex-col gap-5">
          <fieldset className="flex flex-col gap-4 rounded-lg border border-border-subtle bg-surface-1 p-4">
            <legend className="text-[13px] font-semibold text-text-primary px-1">Profile Information</legend>
            <div>
              <label className="mb-1.5 block text-[11px] font-medium text-text-secondary">Email</label>
              <input type="text" readOnly value={profile?.id ? '' : ''}
                className="h-9 w-full rounded-md border border-border-base bg-surface-2 px-3 text-[13px] text-text-tertiary cursor-not-allowed"
                placeholder="Managed by authentication provider" />
              <p className="mt-1 text-[10px] text-text-tertiary">Email cannot be changed here</p>
            </div>
            <div>
              <label className="mb-1.5 block text-[11px] font-medium text-text-secondary">Display Name</label>
              <input type="text" value={displayName} onChange={e => setDisplayName(e.target.value)}
                className="h-9 w-full rounded-md border border-border-base bg-surface-1 px-3 text-[13px] text-text-primary focus:border-amber focus:outline-none"
                placeholder="Your display name" />
            </div>
            <div>
              <label className="mb-1.5 block text-[11px] font-medium text-text-secondary">Avatar URL</label>
              <input type="url" value={avatarUrl} onChange={e => setAvatarUrl(e.target.value)}
                className="h-9 w-full rounded-md border border-border-base bg-surface-1 px-3 text-[13px] text-text-primary focus:border-amber focus:outline-none"
                placeholder="https://..." />
              {avatarUrl && (
                <div className="mt-2 flex items-center gap-2">
                  <img src={avatarUrl} alt="Avatar preview" className="h-8 w-8 rounded-full object-cover border border-border-subtle" onError={e => (e.currentTarget.style.display = 'none')} />
                  <span className="text-[11px] text-text-tertiary">Preview</span>
                </div>
              )}
            </div>
          </fieldset>

          <div className="flex items-center gap-3">
            <button type="submit" disabled={saving}
              className="flex items-center gap-2 rounded-md bg-amber px-5 py-2 text-[13px] font-semibold text-primary-foreground hover:bg-amber-hover disabled:opacity-50 transition-colors">
              {saving ? <Loader2 className="h-4 w-4 animate-spin" /> : <Save className="h-4 w-4" />}
              Save Profile
            </button>
          </div>
        </form>
      )}

      {/* Workspace Tab */}
      {tab === 'workspace' && (
        <div className="flex flex-col gap-5">
          <form onSubmit={saveWorkspace} className="flex flex-col gap-5">
            <fieldset className="flex flex-col gap-4 rounded-lg border border-border-subtle bg-surface-1 p-4">
              <legend className="text-[13px] font-semibold text-text-primary px-1">Workspace Settings</legend>
              <div>
                <label className="mb-1.5 block text-[11px] font-medium text-text-secondary">Workspace Name</label>
                <input type="text" value={wsName} onChange={e => setWsName(e.target.value)} required
                  className="h-9 w-full rounded-md border border-border-base bg-surface-1 px-3 text-[13px] text-text-primary focus:border-amber focus:outline-none" />
              </div>
              <div>
                <label className="mb-1.5 block text-[11px] font-medium text-text-secondary">Slug</label>
                <input type="text" value={wsSlug} onChange={e => setWsSlug(e.target.value)}
                  className="h-9 w-full rounded-md border border-border-base bg-surface-1 px-3 font-mono text-[13px] text-text-primary focus:border-amber focus:outline-none"
                  placeholder="my-workspace" />
              </div>
              <div>
                <label className="mb-1.5 block text-[11px] font-medium text-text-secondary">Plan</label>
                <div className="flex items-center gap-2">
                  <span className={cn("rounded-full px-2.5 py-0.5 text-[11px] font-bold",
                    workspace?.plan === 'scale' ? "bg-amber/15 text-amber" :
                    workspace?.plan === 'pro' ? "bg-blue-400/15 text-blue-400" :
                    "bg-surface-2 text-text-tertiary"
                  )}>
                    {workspace?.plan || 'free'}
                  </span>
                </div>
              </div>
            </fieldset>

            <div className="flex items-center gap-3">
              <button type="submit" disabled={saving || !wsName.trim()}
                className="flex items-center gap-2 rounded-md bg-amber px-5 py-2 text-[13px] font-semibold text-primary-foreground hover:bg-amber-hover disabled:opacity-50 transition-colors">
                {saving ? <Loader2 className="h-4 w-4 animate-spin" /> : <Save className="h-4 w-4" />}
                Save Workspace
              </button>
            </div>
          </form>

          {/* Danger Zone */}
          <fieldset className="flex flex-col gap-3 rounded-lg border border-red-400/30 bg-red-400/5 p-4">
            <legend className="text-[13px] font-semibold text-red-400 px-1">Danger Zone</legend>
            <p className="text-[12px] text-text-secondary">Deleting your workspace is permanent and cannot be undone. All agents, integrations, and data will be destroyed.</p>
            <button disabled
              className="flex items-center gap-1.5 self-start rounded-md border border-red-400/30 bg-red-400/10 px-3 py-1.5 text-[12px] font-medium text-red-400 opacity-60 cursor-not-allowed">
              <Trash2 className="h-3.5 w-3.5" /> Delete Workspace
            </button>
            <p className="text-[10px] text-text-tertiary">Contact support to delete your workspace</p>
          </fieldset>
        </div>
      )}

      {/* Security Tab */}
      {tab === 'security' && (
        <form onSubmit={changePassword} className="flex flex-col gap-5">
          <fieldset className="flex flex-col gap-4 rounded-lg border border-border-subtle bg-surface-1 p-4">
            <legend className="text-[13px] font-semibold text-text-primary px-1">Change Password</legend>
            <div>
              <label className="mb-1.5 block text-[11px] font-medium text-text-secondary">New Password</label>
              <input type="password" value={newPassword} onChange={e => setNewPassword(e.target.value)} minLength={8} required
                className="h-9 w-full rounded-md border border-border-base bg-surface-1 px-3 text-[13px] text-text-primary focus:border-amber focus:outline-none"
                placeholder="Minimum 8 characters" />
            </div>
            <div>
              <label className="mb-1.5 block text-[11px] font-medium text-text-secondary">Confirm Password</label>
              <input type="password" value={confirmPassword} onChange={e => setConfirmPassword(e.target.value)} minLength={8} required
                className={cn("h-9 w-full rounded-md border bg-surface-1 px-3 text-[13px] text-text-primary focus:outline-none",
                  confirmPassword && confirmPassword !== newPassword ? "border-red-400 focus:border-red-400" : "border-border-base focus:border-amber"
                )} />
              {confirmPassword && confirmPassword !== newPassword && (
                <p className="mt-1 text-[10px] text-red-400">Passwords do not match</p>
              )}
            </div>
          </fieldset>

          <div className="flex items-center gap-3">
            <button type="submit" disabled={saving || !newPassword || newPassword !== confirmPassword}
              className="flex items-center gap-2 rounded-md bg-amber px-5 py-2 text-[13px] font-semibold text-primary-foreground hover:bg-amber-hover disabled:opacity-50 transition-colors">
              {saving ? <Loader2 className="h-4 w-4 animate-spin" /> : <Shield className="h-4 w-4" />}
              Update Password
            </button>
          </div>
        </form>
      )}
    </div>
  )
}

import { createClient } from '@/lib/supabase/server'
import { NextRequest } from 'next/server'

export async function POST(
  req: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  const { id } = await params
  const supabase = await createClient()
  const { data: { user } } = await supabase.auth.getUser()
  if (!user) return Response.json({ error: 'unauthorized' }, { status: 401 })

  // Get agent and profile for workspace_id
  const { data: profile } = await supabase
    .from('profiles')
    .select('workspace_id')
    .eq('id', user.id)
    .single()

  if (!profile) return Response.json({ error: 'no_profile' }, { status: 400 })

  // Create a run
  const { data: run, error: runError } = await supabase
    .from('agent_runs')
    .insert({
      agent_id: id,
      workspace_id: profile.workspace_id,
      triggered_by: 'manual',
      status: 'running',
    })
    .select()
    .single()

  if (runError) return Response.json({ error: runError.message }, { status: 400 })

  // Update agent status to running
  await supabase
    .from('agents')
    .update({ status: 'running', last_run_at: new Date().toISOString() })
    .eq('id', id)

  // Increment run_count
  const { data: agent } = await supabase
    .from('agents')
    .select('run_count')
    .eq('id', id)
    .single()
  if (agent) {
    await supabase
      .from('agents')
      .update({ run_count: (agent.run_count || 0) + 1 })
      .eq('id', id)
  }

  return Response.json(run)
}

import { createClient } from '@/lib/supabase/server'
import { NextRequest } from 'next/server'

export async function PATCH(
  req: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  const { id } = await params
  const supabase = await createClient()
  const { data: { user } } = await supabase.auth.getUser()
  if (!user) return Response.json({ error: 'unauthorized' }, { status: 401 })

  const { status } = await req.json()

  const validStatuses = ['idle', 'running', 'paused', 'error', 'archived']
  if (!validStatuses.includes(status)) {
    return Response.json({ error: 'invalid_status' }, { status: 400 })
  }

  const { data, error } = await supabase
    .from('agents')
    .update({ status, updated_at: new Date().toISOString() })
    .eq('id', id)
    .select()
    .single()

  if (error) return Response.json({ error: error.message }, { status: 400 })
  return Response.json(data)
}

import { createClient } from '@/lib/supabase/server'
import { NextRequest } from 'next/server'

export async function POST(
  req: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  const { id } = await params
  const supabase = await createClient()
  const { data: { user } } = await supabase.auth.getUser()
  if (!user) return Response.json({ error: 'unauthorized' }, { status: 401 })

  const { decision, note, editContent } = await req.json()

  const { data, error } = await supabase.rpc('review_approval', {
    p_approval_id: id,
    p_decision: decision,
    p_note: note ?? null,
    p_edit_content: editContent ?? null,
  })

  if (error) return Response.json({ error: error.message }, { status: 400 })
  return Response.json(data)
}

import { createClient } from '@/lib/supabase/server'

export async function GET() {
  const supabase = await createClient()
  await supabase.from('workspaces').select('id').limit(1)
  return Response.json({ ok: true, ts: new Date().toISOString() })
}

import { createServiceRoleClient } from '@/lib/supabase/service'
import { NextRequest } from 'next/server'

export async function POST(
  req: NextRequest,
  { params }: { params: Promise<{ agentId: string }> }
) {
  try {
    const { agentId } = await params
    const body = await req.json()
    const supabase = createServiceRoleClient()

    // Verify agent exists and has webhook trigger
    const { data: agent, error: agentError } = await supabase
      .from('agents')
      .select('id, workspace_id, status')
      .eq('id', agentId)
      .eq('trigger_type', 'webhook')
      .single()

    if (!agent || agentError) {
      return Response.json({ error: 'not_found' }, { status: 404 })
    }

    if (agent.status === 'archived') {
      return Response.json({ error: 'agent_archived' }, { status: 410 })
    }

    // Create a run
    const { error: runError } = await supabase.from('agent_runs').insert({
      agent_id: agent.id,
      workspace_id: agent.workspace_id,
      triggered_by: 'webhook',
      status: 'running',
      metadata: { webhook_payload: body },
    })

    if (runError) {
      return Response.json({ error: runError.message }, { status: 500 })
    }

    // Update agent status
    await supabase
      .from('agents')
      .update({ status: 'running' })
      .eq('id', agent.id)

    return Response.json({ received: true })
  } catch {
    return Response.json({ error: 'invalid_payload' }, { status: 400 })
  }
}

import { createServerClient } from '@supabase/ssr'
import { cookies } from 'next/headers'
import { NextResponse } from 'next/server'

/**
 * POST /api/workspace/provision
 *
 * Called after auth callback to ensure the authenticated user
 * has a workspace + membership. If they don't, create one.
 *
 * This fixes the "dead-end" where handle_new_user() creates a
 * profile row but no workspace, causing my_workspace_id() to
 * return NULL and all RLS policies to block.
 */
export async function POST() {
  const cookieStore = await cookies()
  const supabase = createServerClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
    {
      cookies: {
        getAll() { return cookieStore.getAll() },
        setAll(cookiesToSet) {
          cookiesToSet.forEach(({ name, value, options }) =>
            cookieStore.set(name, value, options))
        },
      },
    }
  )

  const { data: { user }, error: userError } = await supabase.auth.getUser()
  if (userError || !user) {
    return NextResponse.json({ error: 'Not authenticated' }, { status: 401 })
  }

  // Check if user already has a workspace membership
  const { data: membership } = await supabase
    .from('workspace_members')
    .select('workspace_id')
    .eq('user_id', user.id)
    .limit(1)
    .maybeSingle()

  if (membership?.workspace_id) {
    return NextResponse.json({ workspace_id: membership.workspace_id, created: false })
  }

  // No workspace found — create one
  const workspaceName =
    user.user_metadata?.workspace_name ||
    `${user.user_metadata?.full_name || user.email?.split('@')[0] || 'My'}'s Workspace`

  // Insert workspace
  const { data: workspace, error: wsError } = await supabase
    .from('workspaces')
    .insert({ name: workspaceName })
    .select('id')
    .single()

  if (wsError || !workspace) {
    // If table doesn't exist yet, just redirect — no DB provisioned yet
    console.error('Workspace creation failed:', wsError?.message)
    return NextResponse.json({ error: 'Workspace creation failed', details: wsError?.message }, { status: 500 })
  }

  // Create membership linking user to workspace as owner
  const { error: memError } = await supabase
    .from('workspace_members')
    .insert({
      workspace_id: workspace.id,
      user_id: user.id,
      role: 'owner',
    })

  if (memError) {
    console.error('Membership creation failed:', memError.message)
    return NextResponse.json({ error: 'Membership creation failed', details: memError.message }, { status: 500 })
  }

  // Ensure profile exists (handle_new_user may have already created this)
  await supabase
    .from('profiles')
    .upsert({
      id: user.id,
      email: user.email,
      full_name: user.user_metadata?.full_name || user.user_metadata?.name || null,
      avatar_url: user.user_metadata?.avatar_url || null,
    }, { onConflict: 'id' })

  return NextResponse.json({ workspace_id: workspace.id, created: true })
}

import { createClient } from '@/lib/supabase/server'

export async function GET() {
  const supabase = await createClient()
  const { data: { user } } = await supabase.auth.getUser()
  if (!user) return Response.json({ error: 'unauthorized' }, { status: 401 })

  const { data, error } = await supabase.rpc('workspace_stats')
  if (error) return Response.json({ error: error.message }, { status: 400 })
  return Response.json(data)
}

import { createServerClient } from '@supabase/ssr'
import { cookies } from 'next/headers'
import { NextResponse } from 'next/server'

export async function GET(request: Request) {
  const { searchParams, origin } = new URL(request.url)
  const code = searchParams.get('code')
  const next = searchParams.get('next') ?? '/cockpit'

  if (code) {
    const cookieStore = await cookies()
    const supabase = createServerClient(
      process.env.NEXT_PUBLIC_SUPABASE_URL!,
      process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
      {
        cookies: {
          getAll() { return cookieStore.getAll() },
          setAll(cookiesToSet) {
            cookiesToSet.forEach(({ name, value, options }) =>
              cookieStore.set(name, value, options))
          },
        },
      }
    )
    const { error } = await supabase.auth.exchangeCodeForSession(code)
    if (!error) {
      // Ensure the user has a workspace (fixes auth dead-end)
      try {
        await fetch(`${origin}/api/workspace/provision`, {
          method: 'POST',
          headers: {
            cookie: cookieStore.getAll().map(c => `${c.name}=${c.value}`).join('; '),
          },
        })
      } catch (e) {
        // Non-fatal — workspace provisioning may not be available yet
        console.error('Workspace provisioning failed:', e)
      }
      return NextResponse.redirect(`${origin}${next}`)
    }
  }

  return NextResponse.redirect(`${origin}/login?error=auth_failed`)
}

