          </button>
        </form>

        <p className="mt-5 text-center text-[13px] text-text-tertiary">
          Already have an account?{" "}
          <Link href="/login" className="font-medium text-amber transition-colors hover:text-amber/80">
            Sign in
          </Link>
        </p>
      </div>
    </div>
  )
}

