    return () => { supabase.removeChannel(channel) }
  }, [workspaceId, onUpdate])
}

'use client'

import { createContext, useContext, useEffect, useState, type ReactNode } from 'react'
import { createClient } from '@/lib/supabase/client'
import type { Workspace, Profile } from '@/lib/types'
import type { User } from '@supabase/supabase-js'

interface WorkspaceContextValue {
  workspace: Workspace | null
  profile: Profile | null
  user: User | null
  isLoading: boolean
  error: string | null
  refetch: () => Promise<void>
}

const WorkspaceContext = createContext<WorkspaceContextValue>({
  workspace: null,
  profile: null,
  user: null,
  isLoading: true,
  error: null,
  refetch: async () => {},
})

export function WorkspaceProvider({ children }: { children: ReactNode }) {
  const [workspace, setWorkspace] = useState<Workspace | null>(null)
  const [profile, setProfile] = useState<Profile | null>(null)
  const [user, setUser] = useState<User | null>(null)
  const [isLoading, setIsLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)

  async function fetchWorkspaceData() {
    const supabase = createClient()

    try {
      const { data: { user: authUser } } = await supabase.auth.getUser()
      if (!authUser) {
        setIsLoading(false)
        return
      }
      setUser(authUser)

      // Fetch profile
      const { data: profileData, error: profileError } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', authUser.id)
        .single()

      if (profileError) {
        setError(profileError.message)
        setIsLoading(false)
        return
      }
      setProfile(profileData)

      // Fetch workspace
      if (profileData?.workspace_id) {
        const { data: workspaceData, error: wsError } = await supabase
          .from('workspaces')
          .select('*')
          .eq('id', profileData.workspace_id)
          .single()

        if (wsError) {
          setError(wsError.message)
        } else {
          setWorkspace(workspaceData)
        }
      }
    } catch (err) {
      setError('Failed to load workspace data')
    } finally {
      setIsLoading(false)
    }
  }

  useEffect(() => {
    fetchWorkspaceData()
  }, [])

  return (
    <WorkspaceContext.Provider value={{ workspace, profile, user, isLoading, error, refetch: fetchWorkspaceData }}>
      {children}
    </WorkspaceContext.Provider>
  )
}

export function useWorkspace() {
  return useContext(WorkspaceContext)
}

import { createBrowserClient } from '@supabase/ssr'

export function createClient() {
  return createBrowserClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!
  )
}

import type { PostgrestError } from '@supabase/supabase-js'
import { toast } from 'sonner'

export function handleSupabaseError(error: PostgrestError): string {
  if (error.code === 'P0010') return 'Agent limit reached for your plan'
  if (error.code === 'P0060') return 'Too many requests, please slow down'
  if (error.code === '42501') return 'Permission denied'
  if (error.code === 'PGRST116') return 'Record not found'
  if (error.code === '23505') return 'A record with that name already exists'
  if (error.code === '23503') return 'Referenced record not found'
  return error.message
}

export function toastError(error: PostgrestError | Error | string) {
  const message =
    typeof error === 'string'
      ? error
      : 'code' in (error as PostgrestError)
        ? handleSupabaseError(error as PostgrestError)
        : (error as Error).message
  toast.error(message)
}

export function toastSuccess(message: string) {
  toast.success(message)
}

"use client"

import { useEffect, useState, useCallback } from "react"
import { createClient } from "./client"
import type { User } from "@supabase/supabase-js"

/* ── Authenticated user hook ── */
export function useUser() {
  const [user, setUser] = useState<User | null>(null)
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    const supabase = createClient()

    supabase.auth.getUser().then(({ data: { user } }) => {
      setUser(user ?? null)
      setLoading(false)
    })

    const {
      data: { subscription },
    } = supabase.auth.onAuthStateChange((_event, session) => {
      setUser(session?.user ?? null)
      setLoading(false)
    })

    return () => subscription.unsubscribe()
  }, [])

  const signOut = useCallback(async () => {
    const supabase = createClient()
    await supabase.auth.signOut()
    window.location.href = "/login"
  }, [])

  return { user, loading, signOut }
}

/* ── User display info helper ── */
export function getUserDisplayInfo(user: User | null) {
  if (!user) return { name: "Guest", email: "", initials: "?" }

  const meta = user.user_metadata ?? {}
  const name =
    meta.full_name ||
    meta.name ||
    meta.preferred_username ||
    user.email?.split("@")[0] ||
    "User"
  const email = user.email || ""
  const initials = name
    .split(" ")
    .map((w: string) => w[0])
    .join("")
    .toUpperCase()
    .slice(0, 2)

  return { name, email, initials }
}

/* ── Generic Supabase table hook ── */
export function useSupabaseQuery<T>(
  table: string,
  options?: {
    select?: string
    orderBy?: string
    ascending?: boolean
    limit?: number
    filters?: Record<string, unknown>
  }
) {
  const [data, setData] = useState<T[]>([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    let cancelled = false
    const supabase = createClient()

    async function fetch() {
      try {
        let query = supabase.from(table).select(options?.select ?? "*")

        if (options?.filters) {
          for (const [key, value] of Object.entries(options.filters)) {
            query = query.eq(key, value)
          }
        }
        if (options?.orderBy) {
          query = query.order(options.orderBy, {
            ascending: options.ascending ?? false,
          })
        }
        if (options?.limit) {
          query = query.limit(options.limit)
        }

        const { data, error } = await query
        if (cancelled) return
        if (error) {
          // Table doesn't exist yet — not an error for the user
          setError(error.message)
          setData([])
        } else {
          setData((data as T[]) ?? [])
        }
      } catch {
        if (!cancelled) setError("Failed to fetch data")
      } finally {
        if (!cancelled) setLoading(false)
      }
    }

    fetch()
    return () => {
      cancelled = true
    }
  }, [table, options?.select, options?.orderBy, options?.ascending, options?.limit])

  return { data, loading, error }
}

import { createServerClient } from '@supabase/ssr'
import { cookies } from 'next/headers'

export async function createClient() {
  const cookieStore = await cookies()
  return createServerClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
    {
      cookies: {
        getAll() { return cookieStore.getAll() },
        setAll(cookiesToSet) {
          try {
            cookiesToSet.forEach(({ name, value, options }) =>
              cookieStore.set(name, value, options))
          } catch {}
        },
      },
    }
  )
}

import { createClient } from '@supabase/supabase-js'

export function createServiceRoleClient() {
  const url = process.env.NEXT_PUBLIC_SUPABASE_URL
  const serviceKey = process.env.SUPABASE_SERVICE_ROLE_KEY

  if (!url || !serviceKey) {
    throw new Error('Missing SUPABASE_SERVICE_ROLE_KEY or NEXT_PUBLIC_SUPABASE_URL')
  }

  return createClient(url, serviceKey, {
    auth: { autoRefreshToken: false, persistSession: false },
  })
}

// Database types matching Supabase schema
export interface Workspace { id: string name: string slug: string plan: string events_quota: number events_used: number stripe_id: string | null created_at: string updated_at: string }
export interface Profile { id: string workspace_id: string full_name: string avatar_url: string | null role: 'owner' | 'admin' | 'member' created_at: string updated_at: string }
export interface DbAgent { id: string workspace_id: string name: string description: string | null role: string | null status: 'idle' | 'running' | 'paused' | 'error' | 'archived' trigger_type: 'manual' | 'schedule' | 'webhook' | 'event' trigger_config: Record<string, unknown> | null approval_mode: 'always' | 'never' | 'risk_above' approval_threshold: 'low' | 'medium' | 'high' | 'critical' | null integrations: string[] | null model: string | null system_prompt: string | null run_count: number last_run_at: string | null created_by: string | null created_at: string updated_at: string }
export interface AgentRun { id: string agent_id: string workspace_id: string status: 'running' | 'completed' | 'success' | 'failed' | 'timeout' | 'cancelled' triggered_by: string | null started_at: string completed_at: string | null duration_ms: number | null action_count: number | null approval_count: number | null cost_usd: number | null error: string | null metadata: Record<string, unknown> | null }
export interface DbApproval { id: string workspace_id: string event_id: string | null agent_id: string | null run_id: string | null status: 'pending' | 'approved' | 'rejected' | 'expired' | 'cancelled' title: string description: string | null risk_level: 'low' | 'medium' | 'high' | 'critical' draft_content: Record<string, unknown> | null context: Record<string, unknown> | null reviewed_by: string | null reviewed_at: string | null review_note: string | null edit_content: Record<string, unknown> | null expires_at: string | null created_at: string // Joined fields agent?: DbAgent }
export interface DbEvent { id: string workspace_id: string agent_id: string | null run_id: string | null type: string | null status: string | null title: string description: string | null target_type: string | null target_id: string | null target_name: string | null integration: string | null risk_level: string | null payload: Record<string, unknown> | null cost_usd: number | null created_at: string // Joined fields agent?: Pick<DbAgent, 'id' | 'name' | 'role'> }
export interface DbIntegration { id: string workspace_id: string provider: string status: 'active' | 'disconnected' | 'error' | 'pending' account_label: string | null scopes: string[] | null access_token: string | null refresh_token: string | null token_expires_at: string | null metadata: Record<string, unknown> | null connected_by: string | null connected_at: string | null last_used_at: string | null }
export interface DbNotification { id: string workspace_id: string profile_id: string | null type: string | null title: string body: string | null link: string | null read: boolean related_id: string | null created_at: string }
export interface DbAuditLog { id: string workspace_id: string actor_id: string | null action: string table_name: string | null record_id: string | null old_data: Record<string, unknown> | null new_data: Record<string, unknown> | null created_at: string // Joined actor?: Pick<Profile, 'id' | 'full_name'> }
